import { MakeLogicType, afterMount, connect, kea, path } from 'kea'

import { projectLogic } from 'scenes/projectLogic'

// Poll while the pending-deletion screen is open so the UI reacts on its own when deletion finishes
// or the workflow's failure recovery clears the lock — without the user having to refresh.
const POLL_INTERVAL_MS = 30_000

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface pendingDeletionLogicActions {
    loadCurrentProject: () => any // projectLogic
}

export type pendingDeletionLogicType = MakeLogicType<{}, pendingDeletionLogicActions>

export const pendingDeletionLogic = kea<pendingDeletionLogicType>([
    path(['scenes', 'project', 'pendingDeletionLogic']),
    connect(() => ({
        actions: [projectLogic, ['loadCurrentProject']],
    })),
    afterMount(({ actions, cache }) => {
        cache.disposables.add(() => {
            const pollTimer = window.setInterval(() => {
                actions.loadCurrentProject()
            }, POLL_INTERVAL_MS)
            return () => clearInterval(pollTimer)
        })
    }),
])
